import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.BYehg5q7.js";const h=JSON.parse('{"title":"Custom Markers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/custom-markers.md","filePath":"guide/custom-markers.md","lastUpdated":1772287587000}'),o={name:"guide/custom-markers.md"};function i(n,e,l,c,d,m){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="custom-markers" tabindex="-1">Custom Markers <a class="header-anchor" href="#custom-markers" aria-label="Permalink to &quot;Custom Markers&quot;">​</a></h1><p>getbased has a built-in schema of 287+ biomarkers across 16 categories. When you import a PDF that contains a result the app doesn&#39;t recognize — a specialty marker, a newer test, or one with an unusual name — it&#39;s automatically created as a <strong>custom marker</strong> rather than being discarded.</p><h2 id="how-custom-markers-are-created" tabindex="-1">How Custom Markers Are Created <a class="header-anchor" href="#how-custom-markers-are-created" aria-label="Permalink to &quot;How Custom Markers Are Created&quot;">​</a></h2><p>During PDF import, the AI identifies any results that don&#39;t match a known marker. For each unrecognized result, the AI suggests:</p><ul><li>A <strong>category</strong> to place it in (e.g., biochemistry, hormones)</li><li>A <strong>name</strong> for the marker (in plain English)</li><li>The <strong>unit</strong> it&#39;s measured in</li><li>A <strong>reference range</strong> (minimum and maximum) based on the lab report or medical knowledge</li></ul><p>These suggestions appear in the import preview with a <strong>blue &quot;New&quot;</strong> badge. You can review them before confirming.</p><h2 id="where-custom-markers-appear" tabindex="-1">Where Custom Markers Appear <a class="header-anchor" href="#where-custom-markers-appear" aria-label="Permalink to &quot;Where Custom Markers Appear&quot;">​</a></h2><p>Once created, custom markers are treated the same as built-in markers throughout the app:</p><ul><li>They appear in <strong>charts</strong> with reference range bands and trend detection</li><li>They show up in <strong>data tables</strong> and the marker <strong>glossary</strong></li><li>They&#39;re included in <strong>AI chat context</strong>, so the assistant knows about them when you ask questions</li><li>They&#39;re exported in your <strong>JSON backup</strong> and restored on import</li><li>They&#39;re included when you import future PDFs — the AI uses them to avoid creating duplicates</li></ul><h2 id="category-assignment" tabindex="-1">Category Assignment <a class="header-anchor" href="#category-assignment" aria-label="Permalink to &quot;Category Assignment&quot;">​</a></h2><p>If a custom marker belongs to a category that doesn&#39;t exist yet in the built-in schema, a new category is created automatically with a bookmark icon. It appears in the sidebar alongside the standard categories.</p><h2 id="specialty-lab-pipeline" tabindex="-1">Specialty Lab Pipeline <a class="header-anchor" href="#specialty-lab-pipeline" aria-label="Permalink to &quot;Specialty Lab Pipeline&quot;">​</a></h2><p>For non-blood tests (OAT, DUTCH, HTMA, etc.), custom markers are created with a <strong>group</strong> field that determines their sidebar placement. The AI assigns test-type-prefixed categories (e.g., <code>oatNutritional</code>, <code>dutchHormones</code>) and groups them under collapsible sidebar headers.</p><p>This means an OAT import creates categories like &quot;Nutritional Markers&quot; and &quot;Microbial Overgrowth&quot; — all organized under an <strong>OAT</strong> header in the sidebar. See <a href="./specialty-labs.html">Specialty Labs</a> for the full details.</p><h2 id="editing-custom-markers" tabindex="-1">Editing Custom Markers <a class="header-anchor" href="#editing-custom-markers" aria-label="Permalink to &quot;Editing Custom Markers&quot;">​</a></h2><p>Custom marker definitions (name, unit, reference range) are set when first created and won&#39;t be overwritten by future imports of the same marker. If you need to update a definition, you can do so by editing your exported JSON file and re-importing it.</p><div class="tip custom-block"><p class="custom-block-title">Niche and specialty markers</p><p>Custom markers work well for less common tests like omega-3 index, micronutrients, organic acids, or functional medicine panels that aren&#39;t in the standard schema. Import the PDF and the AI handles the mapping automatically.</p></div><div class="tip custom-block"><p class="custom-block-title">Duplicate prevention</p><p>The AI is aware of all existing custom markers when processing new PDFs. It won&#39;t create a second definition for a marker that already exists, even if the name appears slightly differently across different lab reports.</p></div>',18)])])}const p=t(o,[["render",i]]);export{h as __pageData,p as default};
